import{_ as o,o as e,c as a,ag as r}from"./chunks/framework.wqPkq5Rj.js";const m=JSON.parse('{"title":"欢迎来到 AI 原生的工作空间","description":"","frontmatter":{},"headers":[],"relativePath":"philosophy.md","filePath":"philosophy.md","lastUpdated":1777169627000}'),p={name:"philosophy.md"};function s(i,t,c,n,d,l){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="欢迎来到-ai-原生的工作空间" tabindex="-1">欢迎来到 AI 原生的工作空间 <a class="header-anchor" href="#欢迎来到-ai-原生的工作空间" aria-label="Permalink to &quot;欢迎来到 AI 原生的工作空间&quot;">​</a></h1><div style="margin:24px 0;"><img src="https://static.moxtcontent.com/public/resource/ai/gen/936b24cb-6f63-40d3-8f93-9443433a8057.png" alt="Moxt" style="height:40px;width:auto;"></div><p>AI Agents 的迅速发展，让一件事变得清晰：每一家公司，都将很快拥有比人类员工多出数百倍的 AI 员工。它们不通过软件界面点击按钮，而是调用 API、读写文件、彼此沟通。</p><p>人与 AI，需要一个新的地方一起工作。<strong>Moxt，就是这样一个 AI 原生的工作空间。</strong></p><hr><h2 id="_01-·-moxt-more-context" tabindex="-1">01 · Moxt = More Context <a class="header-anchor" href="#_01-·-moxt-more-context" aria-label="Permalink to &quot;01 · Moxt = More Context&quot;">​</a></h2><p>你试过让 AI 读你们公司的文档吗？它大概能回答问题——但又像没真正懂你的业务。Moxt 围绕一个理念：从 AI 的角度出发，为 AI 同事提供更好的工作环境。</p><p><img src="https://static.moxtcontent.com/public/resource/ai/gen/10880281-3bbf-47d8-95d8-688fa96a30c8.jpeg" alt="More Context"></p><div class="tip custom-block"><p class="custom-block-title">让 AI 在它的母语里工作</p><p>PDF、Word、PPT，AI 读这些就像人类在读一份扫描了三次的传真。在 Moxt，所有内容都转换成 <code>.md</code>、<code>.csv</code>、<code>.html</code> 等 AI 完全理解的格式，代码也可无缝接入。</p></div><div class="tip custom-block"><p class="custom-block-title">让 AI 在熟悉的图书馆里工作</p><p>文件系统，一层层目录，一个个文件，是 AI 训练时最熟悉的知识组织方式。AI 在 Moxt 中导航，就像在自己最熟悉的环境找东西。</p></div><div class="tip custom-block"><p class="custom-block-title">让 AI 都有自己的云端电脑</p><p>Moxt 中的每一位 AI 同事都能随时运行云端电脑：打开浏览器、读写文件、运行代码，把任务从头做到尾。它们不只是在完成任务，而是和你一起共建这个工作空间。</p></div><p>当这三件事同时达成，魔法自然浮现。以下可以成为你在 Moxt 中日常的对话——</p><blockquote><p>&quot;这周五要和老用户复盘，他们当时入场有三个顾虑——你还记得吗？这几个月我们为他们做了哪些事？&quot;</p></blockquote><blockquote><p>&quot;我刚看到竞品发了定价调整公告，结合我们上个月的讨论，你觉得对我们的策略有什么影响？&quot;</p></blockquote><blockquote><p>&quot;你可以去看看未来一个月产品要发布哪些新功能，为我草拟一份品牌营销方案吗？&quot;</p></blockquote><hr><h2 id="_02-·-you-are-not-limited-by-yourself-now" tabindex="-1">02 · You are not limited by yourself now <a class="header-anchor" href="#_02-·-you-are-not-limited-by-yourself-now" aria-label="Permalink to &quot;02 · You are not limited by yourself now&quot;">​</a></h2><p>纳瓦尔说，杠杆是一切伟大成就的底层。momo，是你专属的新型杠杆。</p><p><img src="https://static.moxtcontent.com/public/resource/ai/gen/43e179a6-4138-4a0d-b791-178e22579044.jpeg" alt="momo"></p><table tabindex="0"><thead><tr><th>特性</th><th>说明</th></tr></thead><tbody><tr><td><strong>永远在线</strong></td><td>没有时间和精力的上限，可以并行处理很多事</td></tr><tr><td><strong>完全了解你</strong></td><td>阅读你所有文档，记着每一次决策。给它一件事，不用解释背景</td></tr><tr><td><strong>放大你的判断</strong></td><td>你的标准、偏好、品味——通过 momo 放大成更大的输出和影响</td></tr><tr><td><strong>会上网，懂外部世界</strong></td><td>自己进行外部搜索，主动查资料、追踪动态。必要时可以接管浏览器</td></tr><tr><td><strong>越用越强</strong></td><td>把积累的判断整理成 Skill，形成 Workspace 专有的能力库</td></tr></tbody></table><p>momo 是你思想和品味的放大器，从此你不再受限于一个人的时间精力。</p><hr><h2 id="_03-·-less-is-more" tabindex="-1">03 · Less is more <a class="header-anchor" href="#_03-·-less-is-more" aria-label="Permalink to &quot;03 · Less is more&quot;">​</a></h2><p>一家成立三年的公司，共享文件夹里是什么样的？如果只留下真正需要的，也许不足 5%。</p><p><img src="https://static.moxtcontent.com/public/resource/ai/gen/f571351b-4858-401b-bb10-37268fd8fb18.jpeg" alt="熵减"></p><p>组织只要在成长，就一定会不断熵增。当 Workspace 充满过时信息，即使是 AI，也无法理解你业务真实的状态。</p><p><strong>Moxt 是可以原生熵减的 Workspace。</strong> AI 同事理解所有文档和文件结构，从全局出发让内容始终保持精简和真实。</p><blockquote><p>从此只称「用户」不称「客户」——AI 同事找出所有相关内容完成更新，不只是替换词，是读懂业务之后的一次全局校准。</p></blockquote><hr><h2 id="_04-·-think-more-think-different" tabindex="-1">04 · Think More. Think Different. <a class="header-anchor" href="#_04-·-think-more-think-different" aria-label="Permalink to &quot;04 · Think More. Think Different.&quot;">​</a></h2><p>5 Whys 是丰田提出的经典思考框架——遇到问题，连问五次「为什么」，从表象找到真因。这是现代管理学的圣经条例，但真正用起来的组织少之又少。</p><p><img src="https://static.moxtcontent.com/public/resource/ai/gen/f4c34c7a-79b6-4464-a3a4-f2d977257db0.jpeg" alt="Think More"></p><p>深度思考需要时间，需要足够的信息，还得凑齐所有能回答你下一个问题的人。</p><p><strong>在 Moxt，这个门槛消失了。</strong> momo 就在旁边，陪你发散，陪你整理，陪你追问。对文档中任意内容，你可以划词引用直接追问，momo 接手处理。</p><p>你的直觉是起点，它把这一小步放大成真正有价值的洞察。</p><hr><h2 id="_05-·-可视化你想要的一切" tabindex="-1">05 · 可视化你想要的一切 <a class="header-anchor" href="#_05-·-可视化你想要的一切" aria-label="Permalink to &quot;05 · 可视化你想要的一切&quot;">​</a></h2><p>这个世界为什么有软件？软件是为&quot;人执行过程&quot;而造的。但在 Moxt，执行是 AI 同事的事。你只需要告诉 momo 你想看到什么。</p><p><img src="https://static.moxtcontent.com/public/resource/ai/gen/bfdc9af2-80b6-48ad-8802-8b31ebf6b55c.jpeg" alt="可视化"></p><p>momo 可以直接生成交互式看板、数据报表、翻页演示文稿、热力地图——所有这些都以 HTML 形式存在你的 Workspace 中，可以直接打开、交互、分享。</p><hr><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>或许，我们根本不需要任何软件。而 Moxt 是什么？它只是一款软件吗？说实话，今天的我无法准确对其定义。</p><p>AI agents 像是一个无比强大的新生命体。在过去数月，这种强大已被科技圈中的极客群体们共同见证。而在今天，我们为大家打开一扇门。我们想用一种简宜的交互方式，让更多人得以看见这种强大。</p><p><strong>这不是未来，这是当下。欢迎来到人机共生的新世界。</strong></p><div style="margin-top:40px;padding-top:24px;border-top:1px solid var(--vp-c-divider);"><p style="font-weight:700;color:var(--vp-c-brand-1);">Ryan</p><p style="font-size:13px;color:var(--vp-c-text-3);">Co-Founder, Moxt</p></div>',46)])])}const u=o(p,[["render",s]]);export{m as __pageData,u as default};
